#include<bits/stdc++.h>
using namespace std;
int root[100010];
struct segment_tree
{
    struct node
    {
        int l,r;
        int lson,rson;
        int max1,id;
    }t[6000010];
    int cnt;
    segment_tree():cnt(0){}
    void pushup(int x)
    {
        t[x].max1=max(t[t[x].lson].max1,t[t[x].rson].max1);
        if(t[x].max1==t[t[x].lson].max1)
        {
            t[x].id=t[t[x].lson].id;
        }
        else
        {
            t[x].id=t[t[x].rson].id;
        }
    }
    void add(int &x,int p,int v,int newl=1,int newr=100000)
    {
        if(x==0)
        {
            x=++cnt;
            t[x].l=newl;
            t[x].r=newr;
            t[x].id=newl;
            t[x].max1=t[x].lson=t[x].rson=0;
        }
        if(t[x].l==t[x].r)
        {
            t[x].max1+=v;
            t[x].id=t[x].l;
            return;
        }
        int mid=(t[x].l+t[x].r)>>1;
        if(p<=mid)
        {
            add(t[x].lson,p,v,newl,mid);
        }
        else
        {
            add(t[x].rson,p,v,mid+1,newr);
        }
        pushup(x);
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(t[x].l==t[x].r)
        {
            t[x].max1+=t[y].max1;
            t[x].id=t[x].l;
            return x;
        }
        t[x].lson=merge(t[x].lson,t[y].lson);
        t[x].rson=merge(t[x].rson,t[y].rson);
        pushup(x);
        return x;
    }
}t;
int ans[100010],d[100010],fa[100010][21],lg[100010],n,m;
vector<int> mp[100010];
vector<pair<int,int>> v[100010];
void dfs(int x,int f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
void dfs1(int x,int f=0)
{
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs1(i,x);
            root[x]=t.merge(root[x],root[i]);
        }
    }
    for(auto i:v[x])
    {
        t.add(root[x],i.first,i.second);
    }
    if(t.t[root[x]].max1)
    {
        ans[x]=t.t[root[x]].id;
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<n;i++)
    {
        lg[i+1]=__lg(i+1);
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    for(int i=1;i<=m;i++)
    {
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        int l=lca(x,y);
        v[x].push_back({z,1});
        v[y].push_back({z,1});
        v[l].push_back({z,-1});
        v[fa[l][0]].push_back({z,-1});
    }
    dfs1(1);
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
